1	const BASE_PRICES: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	};
7	
8	const FIRST_INSURANCE_SURCHARGE_NUM = 11;
9	const FIRST_INSURANCE_SURCHARGE_DEN = 10;
10	const FIXED_FEE = 5;
11	
12	export function runScenario(scenario: any): unknown {
13	  const item = scenario.steps[0].items[0];
14	  const basePrice = BASE_PRICES[item.type];
15	  const surcharged = Math.ceil(
16	    (basePrice * FIRST_INSURANCE_SURCHARGE_NUM) / FIRST_INSURANCE_SURCHARGE_DEN
17	  );
18	  const premium = surcharged + FIXED_FEE;
19	  return { results: [{ premium }] };
20	}
